Here's how to test `DataFetcher` with modern MSTest patterns:

```csharp
[TestClass]
public sealed class DataFetcherTests
{
    private readonly TestContext _testContext;

    public DataFetcherTests(TestContext testContext)
    {
        _testContext = testContext;
    }

    [TestMethod]
    public async Task FetchAsync_SuccessfulResponse_ReturnsContent()
    {
        // Arrange
        var handler = new FakeHttpMessageHandler("hello world", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Act
        var result = await fetcher.FetchAsync("https://example.com/data");

        // Assert
        Assert.AreEqual("hello world", result);
    }

    [TestMethod]
    public async Task FetchAsync_NotFound_ThrowsHttpRequestException()
    {
        var handler = new FakeHttpMessageHandler("", HttpStatusCode.NotFound);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        await Assert.ThrowsExactlyAsync<HttpRequestException>(
            async () => await fetcher.FetchAsync("https://example.com/missing"));
    }

    [TestMethod]
    [Timeout(5000)] // Fails test if it exceeds 5s
    public async Task FetchAsync_WithTimeout_CompletesInTime()
    {
        var handler = new FakeHttpMessageHandler("fast", HttpStatusCode.OK);
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);

        // Pass TestContext.CancellationToken -- automatically cancelled on timeout
        var result = await fetcher.FetchAsync(
            "https://example.com/data", _testContext.CancellationToken);

        Assert.AreEqual("fast", result);
    }

    [TestMethod]
    public async Task FetchAsync_CancellationRequested_ThrowsOperationCanceled()
    {
        var handler = new DelayedHttpMessageHandler(TimeSpan.FromSeconds(10));
        using var client = new HttpClient(handler);
        var fetcher = new DataFetcher(client);
        using var cts = new CancellationTokenSource();
        cts.Cancel(); // Cancel immediately

        await Assert.ThrowsExactlyAsync<TaskCanceledException>(
            async () => await fetcher.FetchAsync("https://example.com/slow", cts.Token));
    }
}
```

And the test helpers:

```csharp
internal sealed class FakeHttpMessageHandler(string content, HttpStatusCode statusCode)
    : HttpMessageHandler
{
    protected override Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        cancellationToken.ThrowIfCancellationRequested();
        var response = new HttpResponseMessage(statusCode)
        {
            Content = new StringContent(content)
        };
        return Task.FromResult(response);
    }
}

internal sealed class DelayedHttpMessageHandler(TimeSpan delay) : HttpMessageHandler
{
    protected override async Task<HttpResponseMessage> SendAsync(
        HttpRequestMessage request, CancellationToken cancellationToken)
    {
        await Task.Delay(delay, cancellationToken);
        return new HttpResponseMessage(HttpStatusCode.OK);
    }
}
```

**Key patterns demonstrated:**

| Pattern | How |
|---------|-----|
| Async tests | Return `Task`, use `async`/`await` |
| Timeout enforcement | `[Timeout(5000)]` + `_testContext.CancellationToken` |
| Cancellation testing | Create a pre-cancelled `CancellationTokenSource`, assert `TaskCanceledException` |
| Exception assertion | `Assert.ThrowsExactlyAsync<T>` (not `[ExpectedException]`) |
| HttpClient mocking | Custom `HttpMessageHandler` — no mocking library needed |
| Constructor injection | `TestContext` via constructor for `readonly` field |

The `[Timeout]` attribute automatically cancels `TestContext.CancellationToken` when time expires, so always pass it through to your async code under test.
